mapper.select:
SELECT b.budget_id, b.budget_code, b.budget_name, b.plan_year, ps.scheme_name, b.total_budget, b.allocated_amount, COALESCE(fp.paid_total, 0) AS actual_paid, (b.allocated_amount - COALESCE(fp.paid_total, 0)) AS deviation_amount, CASE WHEN b.allocated_amount > 0 THEN ROUND((COALESCE(fp.paid_total, 0) / b.allocated_amount) * 100, 2) ELSE 0 END AS deviation_rate, CASE WHEN b.allocated_amount > 0 THEN ROUND((COALESCE(fp.paid_total, 0) / b.allocated_amount) * 100, 2) ELSE 0 END AS execution_rate, b.budget_status FROM invest_budget b LEFT JOIN invest_fund_plan fp ON b.budget_id = fp.budget_id LEFT JOIN plan_scheme ps ON b.scheme_id = ps.scheme_id WHERE b.del_flag = '0' AND b.budget_status IN ('2', '3')
AND b.plan_year = #{planYear}
AND b.scheme_id = #{schemeId}
AND b.budget_id = #{budgetId}
AND (b.budget_code LIKE CONCAT('%', #{keyword}, '%') OR b.budget_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.plan_year DESC, b.budget_code

SELECT b.budget_id, b.budget_code, b.budget_name, b.plan_year, ps.scheme_name, b.total_budget, b.allocated_amount, COALESCE(SUM(fp.paid_total), 0) AS actual_paid, (b.allocated_amount - COALESCE(SUM(fp.paid_total), 0)) AS deviation_amount, CASE WHEN b.allocated_amount > 0 THEN ROUND((COALESCE(SUM(fp.paid_total), 0) / b.allocated_amount) * 100, 2) ELSE 0 END AS execution_rate, b.budget_status FROM invest_budget b LEFT JOIN invest_fund_plan fp ON b.budget_id = fp.budget_id LEFT JOIN plan_scheme ps ON b.scheme_id = ps.scheme_id WHERE b.del_flag = '0' AND b.budget_status IN ('2', '3')
AND b.plan_year = #{planYear}
GROUP BY b.budget_id, b.budget_code, b.budget_name, b.plan_year, ps.scheme_name, b.total_budget, b.allocated_amount, b.budget_status ORDER BY b.plan_year DESC, b.budget_code
